import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"Visual Overhaul Design: 壺中の毒 · 大逃杀","description":"","frontmatter":{},"headers":[],"relativePath":"plans/2026-03-22-visual-overhaul-design.md","filePath":"plans/2026-03-22-visual-overhaul-design.md","lastUpdated":null}'),d={name:"plans/2026-03-22-visual-overhaul-design.md"};function n(i,e,l,s,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="visual-overhaul-design-壺中の毒-·-大逃杀" tabindex="-1">Visual Overhaul Design: 壺中の毒 · 大逃杀 <a class="header-anchor" href="#visual-overhaul-design-壺中の毒-·-大逃杀" aria-label="Permalink to &quot;Visual Overhaul Design: 壺中の毒 · 大逃杀&quot;">​</a></h1><h2 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to &quot;Goal&quot;">​</a></h2><p>Transform the chat rendering from flat uniform text into an immersive &quot;surveillance terminal&quot; experience with rich typography, atmospheric effects, and content-aware styling.</p><h2 id="design-decisions" tabindex="-1">Design Decisions <a class="header-anchor" href="#design-decisions" aria-label="Permalink to &quot;Design Decisions&quot;">​</a></h2><h3 id="_1-dual-font-system" tabindex="-1">1. Dual Font System <a class="header-anchor" href="#_1-dual-font-system" aria-label="Permalink to &quot;1. Dual Font System&quot;">​</a></h3><ul><li><strong>Narrative</strong> (serif): <code>Noto Serif SC, Songti SC, Georgia, serif</code> — story, dialogue, inner thoughts</li><li><strong>System</strong> (mono): <code>SF Mono, Consolas, Courier New, monospace</code> — status headers, kill broadcasts data, rules, HUD, terminal messages</li><li>System text color: <strong>amber-green <code>#7a9a6a</code></strong> (harmonizes with existing gold palette)</li></ul><h3 id="_2-atmospheric-layer-css-overlays-on-message-area" tabindex="-1">2. Atmospheric Layer (CSS overlays on message area) <a class="header-anchor" href="#_2-atmospheric-layer-css-overlays-on-message-area" aria-label="Permalink to &quot;2. Atmospheric Layer (CSS overlays on message area)&quot;">​</a></h3><ul><li><strong>Vignette</strong>: <code>radial-gradient(ellipse at center, #1a1814 0%, #050504 100%)</code> on container background</li><li><strong>CRT scanlines</strong>: <code>repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,.03) 2px, rgba(0,0,0,.03) 4px)</code> overlay, pointer-events:none</li><li>Existing paper texture opacity bumped from .04 to .06</li></ul><h3 id="_3-color-palette-update" tabindex="-1">3. Color Palette Update <a class="header-anchor" href="#_3-color-palette-update" aria-label="Permalink to &quot;3. Color Palette Update&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Token</th><th>Old</th><th>New</th><th>Usage</th></tr></thead><tbody><tr><td>blood/death</td><td><code>#a03020</code></td><td><code>#8a0303</code></td><td>Dead names, kill broadcasts, low HP</td></tr><tr><td>system text</td><td><code>#8a6a3a</code> (gold)</td><td><code>#7a9a6a</code> (amber-green)</td><td>Status headers, rules, terminal</td></tr><tr><td>panel glow</td><td>none</td><td><code>boxShadow: 0 0 10px rgba(138,106,58,.15), inset 0 0 1px rgba(255,255,255,.08)</code></td><td>Floating tactical panel feel</td></tr></tbody></table><h3 id="_4-rich-text-rendering-messagerenderer" tabindex="-1">4. Rich Text Rendering (messageRenderer) <a class="header-anchor" href="#_4-rich-text-rendering-messagerenderer" aria-label="Permalink to &quot;4. Rich Text Rendering (messageRenderer)&quot;">​</a></h3><p>Auto-detect patterns in message content and apply styled rendering:</p><table tabindex="0"><thead><tr><th>Pattern</th><th>Detection</th><th>Rendering</th></tr></thead><tbody><tr><td><code>【第X日 | 存活:...| KP:...】</code></td><td>Regex</td><td>Large monospace, amber-green, centered, scanline bg</td></tr><tr><td><code>【击杀播报】...</code></td><td>indexOf (existing)</td><td>Dark red bg, monospace header, blood border, flicker (existing enhanced)</td></tr><tr><td><code>「dialogue」</code></td><td>Regex <code>「...」</code></td><td>Serif, slightly larger, gold quote marks, subtle left indent</td></tr><tr><td><code>♠佐倉井の心声：...♠</code></td><td>Regex (existing)</td><td>Ink blot hidden text (keep existing)</td></tr><tr><td>Terminal/権藤 messages</td><td>Detect <code>「発信者：権藤」</code> or similar</td><td>Monospace, amber-green, terminal-style box with border</td></tr><tr><td><code>**bold**</code></td><td>Markdown</td><td>Bold + slight color brightening</td></tr><tr><td><code>*italic*</code></td><td>Markdown</td><td>Italic, used for inner thoughts</td></tr><tr><td><code># Heading</code></td><td>Markdown</td><td>Large text, centered, wide letter-spacing</td></tr><tr><td><code>&gt; Quote</code></td><td>Markdown</td><td>Left border + indent + darker bg strip</td></tr><tr><td><code>---</code></td><td>Markdown</td><td>Decorative separator line</td></tr></tbody></table><p>Processing order: extract ♠心声♠ first → split by patterns → render each segment with appropriate style.</p><h3 id="_5-greeting-content-enhancement" tabindex="-1">5. Greeting Content Enhancement <a class="header-anchor" href="#_5-greeting-content-enhancement" aria-label="Permalink to &quot;5. Greeting Content Enhancement&quot;">​</a></h3><p>Modify greeting entries to use Markdown + detectable patterns:</p><ul><li>Status header on its own line: <code>【第1日 | 存活: 40/40】</code></li><li>Use <code>**bold**</code> for dramatic emphasis</li><li>Use <code>---</code> for scene breaks</li><li>Use <code>&gt;</code> for flashback/memory segments</li><li>Rules section wrapped in detectable pattern for terminal styling</li></ul><h3 id="_6-customcomponent-color-sync" tabindex="-1">6. CustomComponent Color Sync <a class="header-anchor" href="#_6-customcomponent-color-sync" aria-label="Permalink to &quot;6. CustomComponent Color Sync&quot;">​</a></h3><p>Update the <code>C</code> object in customComponent to match new palette:</p><ul><li><code>blood</code> / <code>red</code> → <code>#8a0303</code></li><li>Panel borders get glow shadow</li><li>No rich text changes needed (game panel is UI, not narrative)</li></ul><h2 id="files-to-modify" tabindex="-1">Files to Modify <a class="header-anchor" href="#files-to-modify" aria-label="Permalink to &quot;Files to Modify&quot;">​</a></h2><ul><li><code>sample card/壺中の毒 · 大逃杀.json</code>: <ul><li>messageRenderer tsxCode (rich text renderer, colors, atmosphere)</li><li>customComponent tsxCode (color sync, panel glow)</li><li>greeting entries content (Markdown markup)</li></ul></li></ul><h2 id="not-in-scope" tabindex="-1">Not In Scope <a class="header-anchor" href="#not-in-scope" aria-label="Permalink to &quot;Not In Scope&quot;">​</a></h2><ul><li>customComponent internal UI layout changes</li><li>New animations beyond color/shadow tweaks</li><li>Font file bundling (all fonts are web-safe or Google Fonts already loaded)</li></ul>',24)])])}const u=t(d,[["render",n]]);export{m as __pageData,u as default};
